    def simplifyBuildingPCAClick(self):
        #Create objects
        a = Algorithms()

        pols = self.Canvas.getPols()
        total = 0
        correct = 0
        if len(pols) > 0:
            mbr_list = []

            for pol in pols:
                mbr_res = a.simplifyBuildingPCA(pol)
                mbr_list.append(mbr_res)
                
                eval_result = a.ResultsEvaluation(pol, a.sigma)
                total += 1
                if eval_result <= 10:
                    correct += 1
            self.Canvas.setMBRs(mbr_list)
        
        else:
            #Get building
            building = self.Canvas.getBuilding()
            
            #Run simplification
            mbr_res = a.simplifyBuildingPCA(building)
            
            #Return results
            self.Canvas.setMBR(mbr_res)
        
            eval_result = a.ResultsEvaluation(building, a.sigma)
            total += 1
            if eval_result <= 10:
                    correct += 1
        
        self.Canvas.repaint()
        self.showEvaluationResults("PCA", total, correct)
        
