    # LOADING  SHAPEFILE - reused the same from assignment #1
    # AI used here for a correction of syntax and creating workflow/pseudocode of choosing, loading .shp and evaluating the results
   
    def showEvaluationResults(self, method_name, total, correct):
        if total == 0:
            return
            
        #Computing the succes rate
        success_rate = (correct / total) * 100
        
        print(f"METHOD: {method_name}")
        print(f"Total number of simplified buildings: {total}")
        print(f"Successfully simplified (deviation to 10°): {correct}")
        print(f"Total accuracy of the method: {success_rate:.1f} %")
        
            #QMessageBox
        msg = QtWidgets.QMessageBox()
        msg.setWindowTitle("Simplification is finished")
        msg.setText(f"Method: {method_name}\n\nTotal accuracy: {success_rate:.1f} %\n\nMore details are shown in the terminal of VSCode.") #AI helped me to create this message box with the results of evaluation
        msg.setIcon(QtWidgets.QMessageBox.Icon.Information)
        msg.setStandardButtons(QtWidgets.QMessageBox.StandardButton.Ok)
        msg.exec()
   
   
   
   
   
    def openFile(self):
        # Pop-up window for searching the shp 
        file_shp, _ = QtWidgets.QFileDialog.getOpenFileName(self.centralwidget, "Open .shp", "", "")
        
        # Then loading .shp
        if file_shp:
            self.loadShapefile(file_shp)

    def loadShapefile(self, file_path):
        # Loading .shp from library
        sf = shapefile.Reader(file_path)
        shapes = sf.shapes()

        # Define initializating value of Min-Max Box of our .shp
        min_x = float('inf')
        max_x = float('-inf')
        min_y = float('inf')
        max_y = float('-inf')
        
        # Determine the min and max points 
        for shape in shapes:
            for point in shape.points:
                if point[0] < min_x: 
                    min_x = point[0]
                if point[0] > max_x: 
                    max_x = point[0]
                if point[1] < min_y: 
                    min_y = point[1]
                if point[1] > max_y: 
                    max_y = point[1]

        print(min_x, max_x, min_y, max_y)
        # Calculating a scale so it fits to the canvas window
        zoom = 600/ max(max_x - min_x, max_y - min_y)

        # Clear canvas
        self.Canvas.clearResult()

        # Create a list of polygons
        list_pols = []


        # Scaling all points in the .shp and creating a polygon
        # +100 sets the new coordinates to left and down so the polygon has stable position
        for shape in shapes:
            pol = QtGui.QPolygonF()
            for point in shape.points:
                x = (point[0] - min_x) * zoom + 50
                y = (max_y - point[1] ) * zoom + 50
            
                pol.append(QtCore.QPointF(x, y))
            list_pols.append(pol)
        self.Canvas.setPols(list_pols)



